/**
 * Tạo prompt ảnh sản phẩm.
 */
export const generateNonFaceImagePrompt = async (
  productName: string,
  scriptPart: string,
  imageStyle: 'Realistic' | '3D' = 'Realistic',
  handVisibility: 'no_hand' | 'with_hand' = 'no_hand',
  visualNote: string = "",
  productParts: any[] = []
): Promise<string> => {
  const ai = getAiClient();
  const is3D = imageStyle === '3D';
  const baseStyle = is3D ? "3D Animation Pixar/Disney style, high-quality polished CGI" : "Photorealistic high-end commercial still life photography, 8k, cinematic studio lighting";

  const handRule = handVisibility === 'with_hand' 
    ? "Show professional, clean human hands holding or interacting with the product. Close-up focus on hand and product."
    : "!!! STRICT RULE: ABSOLUTELY NO PEOPLE, NO HANDS, NO HUMANS, NO MODELS, NO BODY PARTS !!!";

  const instructionText = `
    Task: Write a technical image generation prompt (in English) for a PRODUCT-FOCUSED scene.
    Focus ONLY on the product: "${productName}" and its professional environment.
    ${handRule}

    Context: "${scriptPart}".
    Style: ${baseStyle}.
    Visual Atmosphere: "${visualNote}".

    Requirements:
    1. Professional commercial photography composition (hero shot, bokeh background, macro details).
    2. Strictly NO TEXT, NO ICON, NO EFFECT in image.

    Return ONLY the English prompt.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: instructionText }, ...productParts.map(p => ({ inlineData: p }))] }
    });
    return response.text?.trim().replace(/\n/g, ' ') || "";
  } catch (error) {
    return "Error generating image prompt.";
  }
};

/**
 * Tạo hình ảnh sản phẩm.
 */
export const generateNonFaceImage = async (
  referenceImageParts: any[], 
  handReferencePart: any | null,
  productName: string,
  scriptPart: string, 
  userCustomPrompt: string | undefined, 
  imageStyle: 'Realistic' | '3D' = 'Realistic', 
  handVisibility: 'no_hand' | 'with_hand' = 'no_hand',
  backgroundNote: string = "",
  visualNote: string = "",
  backgroundReferencePart: any | null = null,
  productAngle: string = "",
  poseLabel: string = ""
): Promise<string> => {
  const ai = getAiClient();
  const is3D = imageStyle === '3D';

  const angleMapping: Record<string, string> = {
    "0": "front view",
    "45": "front-right quarter view",
    "90": "right side view",
    "270": "left side view",
    "315": "front-left quarter view"
  };
  const angleLabel = angleMapping[productAngle] || "";

  const baseStyle = is3D 
    ? "Phong cách Hoạt hình 3D chất lượng cao Pixar Style, màu sắc rực rỡ, CGI trau chuốt."
    : "Ảnh chụp sản phẩm thương mại RAW PHOTO, Still Life chuyên nghiệp, 8k, cinematic lighting.";

  let handRule = "";
  if (handVisibility === 'with_hand') {
    handRule = `Góc máy có xuất hiện bàn tay người đang cầm hoặc tương tác với sản phẩm một cách khéo léo và thẩm mỹ. ${handReferencePart ? "Sử dụng bàn tay từ ảnh HAND_REFERENCE làm mẫu." : ""}`;
  } else {
    handRule = "!!! CẢNH BÁO TỐI QUAN TRỌNG: TUYỆT ĐỐI KHÔNG CÓ NGƯỜI, KHÔNG CÓ BẤT KỲ BỘ PHẬN CƠ THỂ NÀO (KHÔNG CÓ TAY CẦM SẢN PHẨM) !!!";
  }

  const poseInstruction = poseLabel ? `PRODUCT DISPLAY STYLE (MANDATORY): The product is ${poseLabel}. Ensure the visual arrangement matches this specific style.` : "";

  const visualRules = `
    ${handRule}
    ${poseInstruction}
    1. CHI TIẾT SẢN PHẨM "${productName}" PHẢI GIỐNG ẢNH THAM CHIẾU 100% (luôn luôn tham chiếu lại hình ảnh sản phẩm mà người dùng tải lên trước khi tạo hình ảnh).
    2. TUYỆT ĐỐI KHÔNG CÓ VĂN BẢN, CHỮ CÁI, LOGO LẠ, ICON, EFFECT, BONG BÓNG CHAT.
    ${angleLabel ? `- Góc nhìn sản phẩm: ${angleLabel}.` : ""}
  `;

  const backgroundRule = backgroundReferencePart 
    ? `MÔI TRƯỜNG: Sử dụng bối cảnh và bố cục từ ảnh BACKGROUND_REFERENCE.`
    : `MÔI TRƯỜNG: Đặt sản phẩm trong bối cảnh ${backgroundNote || 'studio cao cấp'}.`;

  const prompt = `
    ${baseStyle} Tỷ lệ khung hình 9:16. 
    ${visualRules}
    ${backgroundRule}
    ${visualNote ? `BỐ CỤC: ${visualNote}.` : ""}
    MÔ TẢ CẢNH: "${scriptPart}". 
    ${userCustomPrompt || ""}
  `;

  const contents: any[] = [{ text: prompt }];
  if (backgroundReferencePart) contents.push({ inlineData: backgroundReferencePart });
  if (handReferencePart) contents.push({ inlineData: handReferencePart });
  referenceImageParts.forEach(part => contents.push({ inlineData: part }));

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts: contents },
      config: { imageConfig: { aspectRatio: "9:16" } }
    });
    const imgPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    if (!imgPart) throw new Error("Fail");
    return `data:image/png;base64,${imgPart.inlineData.data}`;
  } catch (error) { throw error; }
};

/**
 * Tạo lời nhắc video tập trung vào SẢN PHẨM (VEO-3).
 */
export const generateNonFaceVeoPrompt = async (
  productName: string, 
  scriptText: string, 
  gender: string, 
  voice: string,
  handVisibility: 'no_hand' | 'with_hand' = 'no_hand',
  productImageBase64?: string,
  generatedImageBase64?: string,
  imageStyle: 'Realistic' | '3D' = 'Realistic'
): Promise<string> => {
  const ai = getAiClient();
  const is3D = imageStyle === '3D';
  const voiceDetail = getVoiceDetailedInstruction(voice);
  const voiceGender = gender === 'Nữ' ? 'Female' : 'Male';

  const handInstruction = handVisibility === 'with_hand'
    ? `- Xuất hiện bàn tay đang cầm hoặc tương tác tinh tế với sản phẩm.`
    : `!!! TUYỆT ĐỐI KHÔNG CÓ NGƯỜI HAY TAY NGƯỜI XUẤT HIỆN TRONG VIDEO !!!`;

  const instructionPrompt = `
  Nhiệm vụ: Viết một lời nhắc (Prompt) chi tiết tạo video AI (VEO-3) dài 8 giây tập trung hoàn toàn vào SẢN PHẨM.
  ${handInstruction}

  CẤU TRÚC PROMPT BẮT BUỘC:
  PHẦN 1: SẢN PHẨM & BỐI CẢNH. Mô tả sản phẩm "${productName}" ở chính giữa khung hình, sắc nét, giữ nguyên tỷ lệ 1:1, không biến dạng. ${is3D ? "3D Pixar Animation style." : "Cinematic Realistic style."} Bối cảnh đồng nhất với ảnh tham chiếu.
  PHẦN 2: CHUYỂN ĐỘNG CAMERA (9:16). Dolly in, Pan hoặc Zoom mượt mà vào sản phẩm 1 cách chuyên nghiệp. Tuyệt đối không thay đổi bối cảnh và sản phẩm suốt 8s. 

  PHẦN 3: LỜI THOẠI (BẮT BUỘC THAM CHIẾU GIỌNG NÓI & ĐỘ TUỔI): 
  ✨ Model performs Voice-over with specific traits: "${voice}" (Technical specs: ${voiceDetail}). 
  Speaker Gender: ${voiceGender}. 
  Script content: "${scriptText}"

  PHẦ4: CHẤT LƯỢNG KỸ THUẬT: 4K, 60fps, Cinematic Studio Lighting. 
  Tuyệt đối không có nhạc nền, Khung hình tại giây 8.0 phải giống hệt khung hình tại giây 6.5.
  Video là một cảnh quay liên tục duy nhất từ đầu đến cuối.

  YÊU CẦU: Trả về 1 dòng Tiếng Anh duy nhất (trừ phần lời thoại). Không xuống dòng.`;

  const contents: any[] = [{ text: instructionPrompt }];
  if (productImageBase64) contents.push({ inlineData: { mimeType: 'image/png', data: productImageBase64.split(',')[1] || productImageBase64 } });
  if (generatedImageBase64) contents.push({ inlineData: { mimeType: 'image/png', data: generatedImageBase64.split(',')[1] || generatedImageBase64 } });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: contents }
    });
    return response.text?.trim().replace(/\n/g, ' ') || "";
  } catch (error) {
    return "Error generating video prompt.";
  }
};

import React, { useState, useEffect, useRef } from 'react';
import * as service from '../services/personification2Service';
import { Personification2Segment, AnalyzedCharacter } from '../types';

declare var JSZip: any;

const VOICE_OPTIONS = [
  "Giọng Bắc 20-40 tuổi",
  "Giọng Nam 20-40 tuổi",
  "Giọng Bắc 50-60 tuổi",
  "Giọng Nam 50-60 tuổi",
  "Giọng Bắc 60-80 tuổi",
  "Giọng Nam 60-80 tuổi"
];

const ADDRESSING_OPTIONS = [
  "em - anh chị",
  "tui - mấy bà",
  "mình - cả nhà",
  "tớ - các cậu",
  "mình - các bạn",
  "tao - mày",
  "tui - mấy ní",
  "tui - các bác",
  "tui - mấy ông",
  "mình - mọi người"
];

const SCENE_COUNT_OPTIONS = Array.from({ length: 21 }, (_, i) => {
    const count = i + 3;
    const seconds = count * 8;
    return { count, label: `${count} cảnh - ${seconds}s` };
});

const Personification2Module: React.FC = () => {
  const storageKey = "personification2_v22_final_limits";
  const [originalScript, setOriginalScript] = useState('');
  const [gender, setGender] = useState('Nữ');
  const [voice, setVoice] = useState(VOICE_OPTIONS[0]);
  const [addressing, setAddressing] = useState('');
  const [imageStyle, setImageStyle] = useState<'Realistic' | '3D'>('Realistic');
  const [personDescription, setPersonDescription] = useState('');
  const [contextNote, setContextNote] = useState('');
  const [sceneCount, setSceneCount] = useState(5);
  const [analyzedCharacters, setAnalyzedCharacters] = useState<AnalyzedCharacter[]>([]);
  const [personPreviews, setPersonPreviews] = useState<string[]>([]);
  const [isAnalyzingPerson, setIsAnalyzingPerson] = useState(false);
  const [isPersonified, setIsPersonified] = useState(true);
  const [isProcessing, setIsProcessing] = useState(false);
  const [segments, setSegments] = useState<Personification2Segment[]>([]);

  const localJsonRef = useRef<HTMLInputElement>(null);
  const segmentFileInputRef = useRef<HTMLInputElement>(null);
  const personInputRef = useRef<HTMLInputElement>(null);
  const [activeSegmentForUpload, setActiveSegmentForUpload] = useState<number | null>(null);

  // Khôi phục dữ liệu từ LocalStorage
  useEffect(() => {
    const saved = localStorage.getItem(storageKey);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setOriginalScript(parsed.originalScript || '');
        setGender(parsed.gender || 'Nữ');
        setVoice(parsed.voice || VOICE_OPTIONS[0]);
        setAddressing(parsed.addressing || '');
        setImageStyle(parsed.imageStyle || 'Realistic');
        setPersonDescription(parsed.personDescription || '');
        setContextNote(parsed.contextNote || '');
        setSceneCount(parsed.sceneCount || 5);
        setAnalyzedCharacters(parsed.analyzedCharacters || []);
        setPersonPreviews(parsed.personPreviews || []);
        setIsPersonified(parsed.isPersonified !== undefined ? parsed.isPersonified : true);
        setSegments((parsed.segments || []).map((s: any) => ({
          ...s,
          speaker: s.speaker || 'Object',
          image: { ...s.image, url: s.image?.url || '', loading: false },
          videoPrompt: { ...s.videoPrompt, loading: false }
        })));
      } catch (e) {}
    }
  }, []);

  // Đồng bộ dữ liệu vào LocalStorage
  useEffect(() => {
    const toSave = { 
      originalScript, gender, voice, addressing, imageStyle,
      personDescription, contextNote, sceneCount, analyzedCharacters,
      personPreviews, isPersonified,
      segments: segments.map(s => ({ 
        ...s, 
        image: { ...s.image, loading: false },
        videoPrompt: { ...s.videoPrompt, loading: false }
      })) 
    };
    try {
      localStorage.setItem(storageKey, JSON.stringify(toSave));
    } catch (e) {}
  }, [originalScript, gender, voice, addressing, imageStyle, personDescription, contextNote, sceneCount, analyzedCharacters, personPreviews, isPersonified, segments]);

  const processImportData = async (importedData: any) => {
    try {
      if (!Array.isArray(importedData) || importedData.length === 0) {
        throw new Error("Dữ liệu JSON không hợp lệ.");
      }
      window.dispatchEvent(new CustomEvent('IMPORT_DATA_PROGRESS', { detail: { percent: 10, complete: false } }));
      const firstItem = importedData[0] || {};
      const inputs = firstItem.inputs || {};
      const settings = inputs.settings || {};
      setOriginalScript(inputs.originalScript || '');
      setPersonDescription(inputs.personDescription || '');
      setContextNote(inputs.contextNote || '');
      setSceneCount(inputs.sceneCount || importedData.length);
      setAnalyzedCharacters(inputs.analyzedCharacters || []);
      setPersonPreviews(inputs.personPreviews || []);
      setGender(settings.gender || 'Nữ');
      setVoice(settings.voice || VOICE_OPTIONS[0]);
      setAddressing(settings.addressing || '');
      setImageStyle(settings.imageStyle || 'Realistic');
      setIsPersonified(settings.isPersonified !== undefined ? settings.isPersonified : true);
      const newSegments: Personification2Segment[] = [];
      for (let i = 0; i < importedData.length; i++) {
        const item = importedData[i];
        if (!item) continue;
        const itemInputs = item.inputs || {};
        const segData = itemInputs.segmentData || {};
        newSegments.push({
          id: i + 1,
          content: item.script || '',
          characterIdea: segData.characterIdea || '',
          speaker: segData.speaker || 'Object',
          image: { url: item.outputImage || '', loading: false },
          videoPrompt: { text: item.videoPrompt || '', loading: false, visible: !!item.videoPrompt }
        });
        const percent = Math.round(((i + 1) / importedData.length) * 100);
        window.dispatchEvent(new CustomEvent('IMPORT_DATA_PROGRESS', { detail: { percent, complete: i === importedData.length - 1 } }));
        await new Promise(r => setTimeout(r, 20));
      }
      setSegments(newSegments);
    } catch (error: any) {
      alert("Lỗi khi nạp dự án!");
      window.dispatchEvent(new CustomEvent('IMPORT_DATA_PROGRESS', { detail: { percent: 100, complete: true } }));
    }
  };

  useEffect(() => {
    const handleGlobalExport = () => {
      const exportData = segments.map((seg, index) => ({
        stt: index + 1,
        inputs: {
          originalScript, personDescription, contextNote, sceneCount,
          analyzedCharacters, personPreviews,
          settings: { gender, voice, addressing, imageStyle, isPersonified },
          segmentData: { characterIdea: seg.characterIdea, speaker: seg.speaker }
        },
        script: seg.content,
        outputImage: seg.image?.url || '',
        videoPrompt: seg.videoPrompt?.text || ''
      }));
      window.dispatchEvent(new CustomEvent('EXPORT_DATA_READY', { detail: { data: exportData, moduleName: 'Nhan_Hoa_2_Project' } }));
    };
    const handleGlobalImport = (e: any) => processImportData(e.detail);
    window.addEventListener('REQUEST_EXPORT_DATA', handleGlobalExport);
    window.addEventListener('REQUEST_IMPORT_DATA', handleGlobalImport);
    return () => {
      window.removeEventListener('REQUEST_EXPORT_DATA', handleGlobalExport);
      window.removeEventListener('REQUEST_IMPORT_DATA', handleGlobalImport);
    };
  }, [segments, originalScript, gender, voice, addressing, imageStyle, personDescription, contextNote, sceneCount, analyzedCharacters, personPreviews, isPersonified]);

  const handleSplitScript = async () => {
    if (!originalScript.trim()) return;
    setIsProcessing(true);
    try {
      const splitTexts = await service.splitScriptIntoSegments(originalScript, voice, addressing, sceneCount);
      setSegments(splitTexts.map((text, i) => ({
        id: i + 1,
        content: text,
        characterIdea: '',
        speaker: 'Object',
        image: { url: '', loading: false },
        videoPrompt: { text: '', loading: false, visible: false }
      })));
    } finally {
      setIsProcessing(false);
    }
  };

  const handleAnalyzePerson = async () => {
    if (!personDescription.trim()) return;
    setIsAnalyzingPerson(true);
    try {
      const characters = await service.analyzePersonDescription(personDescription);
      setAnalyzedCharacters(characters);
    } finally {
      setIsAnalyzingPerson(false);
    }
  };

  const handleDeleteCharacter = (e: React.MouseEvent, idx: number) => {
    e.preventDefault();
    e.stopPropagation();
    setAnalyzedCharacters(prev => prev.filter((_, i) => i !== idx));
  };

  const handlePersonFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (files) {
      const readers = Array.from(files).slice(0, 2).map(file => {
        return new Promise<string>((resolve) => {
          const reader = new FileReader();
          reader.onload = (ev) => resolve(ev.target?.result as string);
          reader.readAsDataURL(file);
        });
      });
      Promise.all(readers).then(urls => {
        setPersonPreviews(prev => [...prev, ...urls].slice(0, 2));
      });
    }
    e.target.value = "";
  };

  const removePersonPreview = (idx: number) => {
    setPersonPreviews(prev => prev.filter((_, i) => i !== idx));
  };

  const handleGenImage = async (id: number) => {
    const seg = segments.find(s => s.id === id);
    if (!seg) return;
    setSegments(prev => prev.map(s => s.id === id ? { ...s, image: { ...s.image, loading: true } } : s));
    try {
      const personParts = personPreviews.map(url => ({
        mimeType: 'image/png',
        data: url.split(',')[1]
      }));
      const url = await service.generatePersonifiedImage(
        seg.content, seg.characterIdea, gender, imageStyle, seg.speaker, isPersonified, seg.speaker, personParts, contextNote
      );
      setSegments(prev => prev.map(s => s.id === id ? { ...s, image: { ...s.image, url, loading: false } } : s));
    } catch (e) {
      setSegments(prev => prev.map(s => s.id === id ? { ...s, image: { ...s.image, loading: false, error: 'Lỗi' } } : s));
    }
  };

  const handleGenPrompt = async (id: number) => {
    const seg = segments.find(s => s.id === id);
    if (!seg) return;
    setSegments(prev => prev.map(s => s.id === id ? { ...s, videoPrompt: { ...s.videoPrompt, loading: true, visible: true } } : s));
    try {
      const prompt = await service.generateVideoPromptV2(
        seg.content, seg.characterIdea, gender, voice, imageStyle, seg.speaker, isPersonified, seg.speaker, seg.image.url
      );
      setSegments(prev => prev.map(s => s.id === id ? { ...s, videoPrompt: { text: prompt, loading: false, visible: true } } : s));
    } catch (e) {
      setSegments(prev => prev.map(s => s.id === id ? { ...s, videoPrompt: { ...s.videoPrompt, loading: false } } : s));
    }
  };

  const handleBulkImage = async () => {
    for (const s of segments) await handleGenImage(s.id);
  };

  const handleBulkPrompt = async () => {
    for (const s of segments) await handleGenPrompt(s.id);
  };

  const downloadAllImagesZip = async () => {
    if (typeof JSZip === 'undefined') return alert("ZIP Lib error");
    const zip = new JSZip();
    let count = 0;
    segments.forEach((s, i) => {
      if (s.image.url) {
        zip.file(`${String(i + 1).padStart(2, '0')}.png`, s.image.url.split(',')[1], { base64: true });
        count++;
      }
    });
    if (count === 0) return alert("Không có ảnh để tải");
    const content = await (zip as any).generateAsync({ type: "blob" }); 
    const link = document.createElement('a');
    link.href = URL.createObjectURL(content as any);
    link.download = `nhan_hoa_2_images.zip`;
    link.click();
  };

  const handleDeleteImage = (id: number) => {
    setSegments(prev => prev.map(s => s.id === id ? { ...s, image: { ...s.image, url: '', loading: false } } : s));
  };

  const handleLocalExportJson = () => {
    const exportData = segments.map((seg, index) => ({
      stt: index + 1,
      inputs: {
        originalScript, personDescription, contextNote, sceneCount,
        analyzedCharacters, personPreviews,
        settings: { gender, voice, addressing, imageStyle, isPersonified },
        segmentData: { characterIdea: seg.characterIdea, speaker: seg.speaker }
      },
      script: seg.content,
      outputImage: seg.image?.url || '',
      videoPrompt: seg.videoPrompt?.text || ''
    }));
    const blob = new Blob([JSON.stringify(exportData, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `nhan_hoa_2_export_${Date.now()}.json`;
    link.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      <input type="file" ref={segmentFileInputRef} className="hidden" accept="image/*" onChange={(e) => {
        const file = e.target.files?.[0];
        if (file && activeSegmentForUpload !== null) {
          const reader = new FileReader();
          reader.onload = (event) => setSegments(prev => prev.map(s => s.id === activeSegmentForUpload ? { ...s, image: { ...s.image, url: event.target?.result as string, loading: false } } : s));
          reader.readAsDataURL(file);
        }
        e.target.value = "";
      }} />

      <div className="bg-white rounded-[2rem] border border-indigo-200 p-8 shadow-sm mb-8">
        <div className="space-y-6">
          <div className="flex justify-between items-center px-1">
             <label className="block text-[10px] font-black text-indigo-400 uppercase tracking-widest flex items-center gap-2">
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" strokeWidth="2.5"/></svg>
                1. Kịch bản văn bản gốc
             </label>
             <span className="text-[10px] font-bold text-purple-500 uppercase tracking-widest">Hybrid Mode 2.0</span>
          </div>
          <textarea 
            value={originalScript}
            onChange={e => setOriginalScript(e.target.value)}
            placeholder="Dán kịch bản của bạn vào đây..."
            className="w-full h-32 p-5 bg-indigo-50/30 border border-indigo-100 rounded-3xl focus:ring-2 focus:ring-indigo-100 outline-none transition-all font-medium text-sm leading-relaxed resize-none shadow-inner"
          />

          <div className="grid grid-cols-1 md:grid-cols-12 gap-6 items-end">
            <div className="md:col-span-2 space-y-1.5">
              <label className="block text-[10px] font-black text-slate-400 uppercase mb-1 px-1">Giới tính</label>
              <select value={gender} onChange={e => setGender(e.target.value)} className="w-full p-3 bg-white border border-indigo-100 rounded-xl font-bold outline-none focus:border-indigo-500 shadow-sm">
                <option value="Nữ">Nữ</option>
                <option value="Nam">Nam</option>
              </select>
            </div>
            <div className="md:col-span-3 space-y-1.5">
              <label className="block text-[10px] font-black text-slate-400 uppercase mb-1 px-1">Vùng miền</label>
              <select value={voice} onChange={e => setVoice(e.target.value)} className="w-full p-3 bg-white border border-indigo-100 rounded-xl font-bold outline-none focus:border-indigo-500 shadow-sm">
                {VOICE_OPTIONS.map(v => <option key={v} value={v}>{v}</option>)}
              </select>
            </div>
            <div className="md:col-span-4 space-y-1.5">
              <label className="block text-[10px] font-black text-slate-400 uppercase mb-1 px-1">Xưng hô</label>
              <input 
                list="nhanhoa2-addr-list"
                value={addressing} 
                onChange={e => setAddressing(e.target.value)}
                placeholder="VD: em - anh chị"
                className="w-full p-3 bg-white border border-indigo-100 rounded-xl font-bold outline-none focus:border-indigo-500 text-sm shadow-sm"
              />
              <datalist id="nhanhoa2-addr-list">
                {ADDRESSING_OPTIONS.map(opt => <option key={opt} value={opt} />)}
              </datalist>
            </div>
            <div className="md:col-span-3 space-y-1.5">
              <label className="block text-[10px] font-black text-slate-400 uppercase mb-1 px-1">Số cảnh</label>
              <select 
                value={sceneCount} 
                onChange={e => setSceneCount(parseInt(e.target.value))} 
                className="w-full p-3 bg-white border border-indigo-100 rounded-xl font-bold text-indigo-600 outline-none focus:border-indigo-500 shadow-sm"
              >
                {SCENE_COUNT_OPTIONS.map(opt => <option key={opt.count} value={opt.count}>{opt.label}</option>)}
              </select>
            </div>
          </div>

          <div className="space-y-4">
            <div className="grid grid-cols-1 md:grid-cols-12 gap-4 items-end">
                <div className="md:col-span-9 space-y-1.5">
                    <label className="block text-[10px] font-black text-indigo-600 uppercase tracking-widest px-1 flex items-center gap-2">
                        <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4.354a4 4 0 110 5.292M15 21H3v-1a6 6 0 0112 0v1zm0 0h6v-1a6 6 0 00-9-5.197" strokeWidth="2.5"/></svg>
                        Nhân vật xuất hiện
                    </label>
                    <input 
                        type="text"
                        value={personDescription}
                        onChange={e => setPersonDescription(e.target.value)}
                        placeholder="VD: Một cô Vy và một anh shipper..."
                        className="w-full p-4 bg-indigo-50/50 border border-indigo-100 rounded-2xl focus:ring-2 focus:ring-indigo-100 outline-none transition-all font-bold text-sm shadow-inner"
                    />
                </div>
                <div className="md:col-span-3">
                    <button 
                        onClick={handleAnalyzePerson}
                        disabled={isAnalyzingPerson || !personDescription.trim()}
                        className="w-full py-4 bg-indigo-600 text-white font-black rounded-2xl shadow-lg hover:bg-indigo-700 transition-all uppercase text-[10px] tracking-widest disabled:opacity-50"
                    >
                        {isAnalyzingPerson ? "ĐANG LẤY TÊN..." : "XÁC NHẬN NHÂN VẬT"}
                    </button>
                </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                <div className="space-y-1.5">
                    <label className="block text-[10px] font-black text-slate-400 uppercase mb-1 px-1">Phong cách bối cảnh</label>
                    <div className="flex bg-slate-50 p-1 rounded-xl border border-indigo-100 h-[46px] shadow-sm">
                        <button onClick={() => setImageStyle('Realistic')} className={`flex-1 py-2 text-[10px] font-black uppercase rounded-lg transition-all ${imageStyle === 'Realistic' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-400 hover:text-slate-600'}`}>Chân thực</button>
                        <button onClick={() => setImageStyle('3D')} className={`flex-1 py-2 text-[10px] font-black uppercase rounded-lg transition-all ${imageStyle === '3D' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-400 hover:text-slate-600'}`}>3D</button>
                    </div>
                </div>
                <div className="space-y-1.5">
                    {analyzedCharacters.length > 0 && (
                        <div className="w-full p-3 bg-purple-50 border border-purple-100 rounded-xl animate-fadeIn">
                            <span className="text-[9px] font-black text-purple-700 uppercase px-1">Danh sách nhân vật:</span>
                            <div className="flex flex-wrap gap-2 mt-2">
                                {analyzedCharacters.map((c, idx) => (
                                    <div key={`${c.name}-${idx}`} className="group relative flex items-center bg-white border border-purple-200 px-3 py-1.5 rounded-full shadow-sm">
                                        <span className="text-[10px] text-purple-800 font-bold uppercase">{c.name}</span>
                                        <button 
                                            onClick={(e) => handleDeleteCharacter(e, idx)}
                                            className="ml-2 w-5 h-5 bg-slate-100 text-slate-400 rounded-full flex items-center justify-center hover:bg-red-500 hover:text-white transition-all text-[10px]"
                                        >✕</button>
                                    </div>
                                ))}
                            </div>
                        </div>
                    )}
                </div>
            </div>

            <div className="p-6 bg-indigo-50/20 border border-indigo-100 rounded-[2rem] space-y-6">
                <div className="space-y-4">
                    <div className="flex justify-between items-center px-1">
                        <label className="text-[10px] font-black text-indigo-500 uppercase tracking-widest flex items-center gap-2">
                           <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" strokeWidth="2.5"/></svg>
                           Ảnh nhân vật mẫu (Khóa ngoại hình)
                        </label>
                    </div>
                    <div className="grid grid-cols-2 md:grid-cols-6 gap-4">
                        {personPreviews.map((url, i) => (
                            <div key={i} className="relative aspect-square rounded-2xl overflow-hidden border border-indigo-200 group shadow-sm">
                                <img src={url} className="w-full h-full object-cover" />
                                <button onClick={() => removePersonPreview(i)} className="absolute top-2 right-2 bg-red-600 text-white p-1 rounded-full opacity-0 group-hover:opacity-100 transition-opacity">
                                    <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" /></svg>
                                </button>
                            </div>
                        ))}
                        {personPreviews.length < 2 && (
                            <div 
                                onClick={() => personInputRef.current?.click()}
                                className="aspect-square border-2 border-dashed border-indigo-300 rounded-2xl flex flex-col items-center justify-center bg-white cursor-pointer hover:border-indigo-400 transition-all group"
                            >
                                <svg className="w-6 h-6 text-indigo-300 group-hover:text-indigo-500" fill="none" stroke="currentColor" viewBox="24 24"><path d="M12 4v16m8-8H4" /></svg>
                                <span className="text-[8px] font-black text-indigo-400 mt-1 uppercase">THÊM ẢNH</span>
                            </div>
                        )}
                    </div>
                    <input type="file" multiple ref={personInputRef} className="hidden" accept="image/*" onChange={handlePersonFileChange} />
                </div>

                <div className="space-y-1.5 border-t border-indigo-100 pt-4">
                    <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest px-1">Ghi chú bối cảnh chung</label>
                    <textarea 
                        value={contextNote}
                        onChange={e => setContextNote(e.target.value)}
                        placeholder="VD: Trong quán cà phê hiện đại, ánh sáng ấm, phong cách vintage..."
                        className="w-full h-20 p-4 bg-white border border-indigo-100 rounded-2xl focus:ring-2 focus:ring-indigo-100 outline-none transition-all text-xs font-medium resize-none shadow-inner"
                    />
                </div>
            </div>
          </div>

          <div className="flex flex-col sm:flex-row items-center justify-between gap-6 pt-4 border-t border-indigo-50 mt-4">
            <button 
              onClick={handleSplitScript}
              disabled={isProcessing || !originalScript.trim()}
              className="w-full sm:w-auto px-12 py-4 bg-indigo-600 text-white font-black rounded-2xl shadow-xl hover:bg-indigo-700 transition-all uppercase tracking-widest disabled:opacity-50 text-sm"
            >
              {isProcessing ? "ĐANG TRIỂN KHAI..." : "TRIỂN KHAI KỊCH BẢN"}
            </button>

            <div className="flex items-center gap-3 px-1">
                 <div className="text-right">
                    <span className={`text-[10px] font-black uppercase block leading-tight transition-colors ${isPersonified ? 'text-indigo-600' : 'text-slate-400'}`}>Nhân hóa vật thể</span>
                    <span className="text-[8px] text-slate-400 font-bold uppercase tracking-tighter">Tắt = Xóa vật thể</span>
                 </div>
                 <button onClick={() => setIsPersonified(!isPersonified)} className={`relative w-14 h-7 rounded-full transition-colors duration-300 ${isPersonified ? 'bg-indigo-600' : 'bg-slate-300'}`}>
                    <div className={`absolute top-1 left-1 w-5 h-5 bg-white rounded-full transition-transform shadow-sm ${isPersonified ? 'translate-x-7' : 'translate-x-0'}`}></div>
                 </button>
            </div>
          </div>
        </div>
      </div>

      {segments.length > 0 && (
        <div className="space-y-12 pb-32">
          <div className="bg-slate-900 p-6 rounded-3xl border border-slate-800 shadow-2xl flex flex-col md:flex-row items-center justify-between gap-6">
              <div className="text-center md:text-left">
                  <h3 className="text-white font-black text-lg uppercase tracking-tight">Kịch bản chi tiết ({segments.length} cảnh)</h3>
                  <p className="text-[10px] text-indigo-400 font-bold uppercase mt-1 tracking-widest">HỆ THỐNG ĐÃ SẴN SÀNG</p>
              </div>
              <div className="flex flex-wrap justify-center gap-3">
                  <button onClick={handleBulkImage} className="px-6 py-3 bg-indigo-600 text-white text-[10px] font-black rounded-xl hover:bg-indigo-700 transition-all uppercase shadow-lg shadow-indigo-900/40">Vẽ tất cả ảnh</button>
                  <button onClick={handleBulkPrompt} className="px-6 py-3 bg-white text-slate-900 text-[10px] font-black rounded-xl hover:bg-slate-100 transition-all uppercase shadow-lg">Viết tất cả prompt</button>
              </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
            {segments.map((seg) => (
                <div key={seg.id} className="bg-white rounded-[2.5rem] border border-slate-200 shadow-sm overflow-hidden flex flex-col h-full group hover:shadow-xl transition-all">
                  <div className="relative aspect-[9/16] bg-slate-100">
                    {seg.image.url ? (
                      <>
                        <img src={seg.image.url} className="w-full h-full object-cover" />
                        <button onClick={() => handleDeleteImage(seg.id)} className="absolute top-4 right-4 w-8 h-8 bg-red-600 text-white rounded-full flex items-center justify-center shadow-lg hover:bg-red-700 transition-all z-10">
                          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" strokeWidth="3"/></svg>
                        </button>
                      </>
                    ) : (
                      <div className="absolute inset-0 flex flex-col items-center justify-center p-6 text-center">
                        <button onClick={() => { setActiveSegmentForUpload(seg.id); segmentFileInputRef.current?.click(); }} className="px-4 py-2 bg-indigo-50 text-indigo-600 rounded-xl text-[10px] font-black hover:bg-indigo-100 transition-all uppercase border border-indigo-100 shadow-sm">Tải ảnh lên</button>
                      </div>
                    )}
                    {seg.image.loading && (
                      <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/5 backdrop-blur-sm z-20">
                        <div className="w-10 h-10 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin shadow-lg"></div>
                        <span className="mt-4 text-[10px] font-black text-indigo-600 uppercase tracking-widest animate-pulse">Đang vẽ...</span>
                      </div>
                    )}
                    <div className="absolute top-4 left-4 bg-indigo-900/80 backdrop-blur-md text-white text-[10px] font-black px-4 py-2 rounded-full shadow-md">CẢNH #{seg.id}</div>
                  </div>

                  <div className="p-6 space-y-4 flex flex-col flex-1">
                    <div className="space-y-1">
                      <div className="flex justify-between items-center px-1">
                         <label className="text-[9px] font-black text-indigo-600 uppercase">Lời thoại {seg.id}:</label>
                         <span className={`text-[10px] px-2 py-0.5 rounded-full font-black tabular-nums shadow-sm ${seg.content.length >= 140 && seg.content.length <= 160 ? 'bg-green-100 text-green-700' : 'bg-red-50 text-red-500'}`}>
                            {seg.content.length}/160
                         </span>
                      </div>
                      <textarea value={seg.content} onChange={e => setSegments(prev => prev.map(s => s.id === seg.id ? { ...s, content: e.target.value } : s))} className="w-full h-24 p-3 bg-slate-50 border border-slate-200 rounded-2xl text-xs font-bold text-slate-700 outline-none focus:bg-white resize-none shadow-inner" />
                    </div>

                    <div className="space-y-3">
                      <div className="space-y-1">
                          <label className="text-[9px] font-black text-purple-600 uppercase px-1">{isPersonified ? "Mô tả vật thể:" : "Vật thể bị ẩn"}</label>
                          <textarea 
                            value={seg.characterIdea} 
                            onChange={e => setSegments(prev => prev.map(s => s.id === seg.id ? { ...s, characterIdea: e.target.value } : s))} 
                            disabled={!isPersonified}
                            placeholder={isPersonified ? "Miếng sườn có tay chân..." : "Không có vật thể..."} 
                            className={`w-full h-16 p-3 border rounded-2xl text-[11px] font-medium outline-none focus:bg-white resize-none shadow-inner ${isPersonified ? 'bg-purple-50/30 border-purple-100' : 'bg-slate-100 border-slate-200 opacity-50'}`} 
                          />
                      </div>

                      <div className="space-y-1">
                          <label className="text-[9px] font-black text-indigo-600 uppercase px-1">Ai đang nói?</label>
                          <select 
                              value={seg.speaker} 
                              onChange={e => setSegments(prev => prev.map(s => s.id === seg.id ? { ...s, speaker: e.target.value } : s))}
                              className="w-full p-2.5 bg-indigo-50 border border-indigo-100 rounded-xl text-[10px] font-black outline-none uppercase text-indigo-700 shadow-sm"
                          >
                              <option value="Object">Vật thể nhân hóa</option>
                              {analyzedCharacters.map((char, idx) => (
                                <option key={`${char.name}-${idx}`} value={char.name}>{char.name}</option>
                              ))}
                          </select>
                      </div>
                    </div>

                    <div className="mt-auto grid grid-cols-2 gap-2 pt-2">
                      <button onClick={() => handleGenImage(seg.id)} disabled={seg.image.loading} className="py-3 bg-indigo-900 text-white text-[10px] font-black rounded-xl uppercase hover:bg-black transition-all shadow-md">Vẽ ảnh</button>
                      <button onClick={() => handleGenPrompt(seg.id)} disabled={seg.videoPrompt.loading} className="py-3 bg-purple-100 text-purple-700 text-[10px] font-black rounded-xl uppercase border border-purple-200 shadow-sm">Prompt</button>
                    </div>
                  </div>

                  {seg.videoPrompt.visible && (
                    <div className="p-4 bg-indigo-950 border-t border-indigo-900 animate-slideUp">
                      <div className="flex justify-between items-center mb-2">
                        <span className="text-[8px] font-black text-purple-400 uppercase tracking-widest">Video Prompt Ready</span>
                        <button onClick={() => navigator.clipboard.writeText(seg.videoPrompt.text)} className="text-[8px] text-white underline font-black uppercase">Copy</button>
                      </div>
                      {seg.videoPrompt.loading ? <div className="h-8 flex items-center justify-center"><div className="w-4 h-4 border-2 border-purple-500 border-t-white rounded-full animate-spin"></div></div> : <p className="text-[9px] text-indigo-200 italic leading-snug">"{seg.videoPrompt.text}"</p>}
                    </div>
                  )}
                </div>
            ))}
          </div>

          <div className="flex flex-col gap-10 py-12 border-t border-indigo-100">
            <div className="flex flex-col md:flex-row items-center justify-center gap-4">
               <button onClick={() => localJsonRef.current?.click()} className="w-full md:w-auto px-10 py-4 bg-indigo-50 text-indigo-600 font-black rounded-2xl border border-indigo-100 hover:bg-indigo-100 transition-all flex items-center justify-center gap-3 uppercase text-[11px] tracking-widest shadow-sm">
                 <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 16v1a2 2 0 002 2h12a2 2 0 002-2v-1M12 12V4m0 0l-3 3m3-3l3 3" strokeWidth="2.5"/></svg>
                 Tải Dự Án (JSON)
               </button>
               <input type="file" ref={localJsonRef} onChange={e => { const file = e.target.files?.[0]; if (file) { const reader = new FileReader(); reader.onload = (event) => processImportData(JSON.parse(event.target?.result as string)); reader.readAsText(file); } e.target.value = ""; }} className="hidden" accept="application/json" />
               <button onClick={handleLocalExportJson} className="w-full md:w-auto px-10 py-4 bg-gradient-to-r from-indigo-600 to-purple-600 text-white font-black rounded-2xl hover:shadow-indigo-200 transition-all flex items-center justify-center gap-3 uppercase text-[11px] tracking-widest shadow-lg">
                 <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 16v1a2 2 0 002 2h12a2 2 0 002-2v-1M12 12V4m0 0l-3 3m3-3l3 3" strokeWidth="2.5"/></svg>
                 Lưu Dự Án (JSON)
               </button>
            </div>
            <div className="flex flex-col md:flex-row items-center justify-center gap-6">
                <button onClick={downloadAllImagesZip} className="w-full md:w-auto px-12 py-5 bg-indigo-900 text-white font-black rounded-3xl shadow-xl hover:bg-black transition-all flex items-center justify-center gap-4 uppercase tracking-widest text-base shadow-indigo-200/20">
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M4 16v1a2 2 0 002 2h12a2 2 0 002-2v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                  Tải bộ ảnh (ZIP)
                </button>
                <button onClick={() => { const text = segments.map(s => s.videoPrompt.text).filter(t => t).join('\n'); const blob = new Blob([text], { type: 'text/plain' }); const link = document.createElement('a'); link.href = URL.createObjectURL(blob); link.download = 'prompts.txt'; link.click(); }} className="w-full md:w-auto px-12 py-5 bg-gradient-to-r from-purple-600 to-indigo-600 text-white font-black rounded-3xl shadow-xl hover:opacity-90 transition-all flex items-center justify-center gap-4 uppercase tracking-widest text-base shadow-indigo-200/20">
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1.01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                  Tải Prompt (TXT)
                </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Personification2Module;

import React, { useState, useEffect, useRef } from 'react';
import { ScriptParts } from '../types';
import * as service from '../services/reviewDoiThoaiService';
import ScriptSection from '../components/ScriptSection';
import ImageCard, { KOC_POSES, CAMERA_ANGLES, CAMERA_SHOTS } from '../components/ImageCard';

declare var JSZip: any;

const VOICE_OPTIONS = ["Giọng Bắc 20-40 tuổi", "Giọng Nam 20-40 tuổi", "Giọng Bắc 50-60 tuổi", "Giọng Nam 50-60 tuổi", "Giọng Bắc 60-80 tuổi", "Giọng Nam 60-80 tuổi"];
const ADDRESSING_OPTIONS = ["em - anh chị", "tui - mấy bà", "mình - mọi người", "con - cô chú", "con - ba mẹ", "cháu - ông bà", "tao - mày"];
const TONE_OPTIONS = ["Hào hứng", "Chân thành", "Kịch tính", "Hài hước", "Chuyên gia", "Nhẹ nhàng", "Thúc giục"];

const SCENE_COUNT_OPTIONS = Array.from({ length: 13 }, (_, i) => ({ count: i + 3, label: `${i + 3} cảnh - ${(i + 3) * 8}s` }));

const SPEAKER_OPTIONS = [
  { value: 'A', label: 'NHÂN VẬT A' },
  { value: 'B', label: 'NHÂN VẬT B' }
];

const ReviewDoiThoaiModule: React.FC = () => {
  const storageKey = "review_doithoai_v24_note_only";
  const [state, setState] = useState<any>({
    charA: { facePreview: null, outfitPreview: null, processedOutfit: null, isExtractingOutfit: false, gender: 'Nữ', voice: VOICE_OPTIONS[0], addressing: 'em - anh chị', description: '' },
    charB: { facePreview: null, outfitPreview: null, processedOutfit: null, isExtractingOutfit: false, gender: 'Nam', voice: VOICE_OPTIONS[1], addressing: 'anh - em', description: '' },
    productFiles: [], productPreviews: [], productName: '', keyword: '',
    sceneCount: 5, backgroundNote: '', imageStyle: 'Realistic', 
    userContent: '', scriptTone: 'Hào hứng',
    isGenerating: false, script: null, images: {}, videoPrompts: {}, sceneChars: {}, sceneSpeakers: {}
  });

  const productInput = useRef<HTMLInputElement>(null);
  const faceAInput = useRef<HTMLInputElement>(null);
  const faceBInput = useRef<HTMLInputElement>(null);
  const outfitAInput = useRef<HTMLInputElement>(null);
  const outfitBInput = useRef<HTMLInputElement>(null);
  const localJsonRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem(storageKey);
    if (saved) {
      try {
        const p = JSON.parse(saved);
        // Đảm bảo sceneCount là number để tránh lỗi React child object
        const safeSceneCount = typeof p.sceneCount === 'object' ? (p.sceneCount.count || 5) : (p.sceneCount || 5);

        setState((prev: any) => ({ 
          ...prev, 
          ...p, 
          sceneCount: safeSceneCount,
          productFiles: [], 
          charA: { ...p.charA, isExtractingOutfit: false }, 
          charB: { ...p.charB, isExtractingOutfit: false }
        }));
      } catch (e) {}
    }
  }, []);

  useEffect(() => {
    try {
      const { productFiles, isGenerating, ...rest } = state;
      localStorage.setItem(storageKey, JSON.stringify(rest));
    } catch (e) {}
  }, [state]);

  const handleExtractOutfit = async (char: 'A' | 'B') => {
    const charData = char === 'A' ? state.charA : state.charB;
    const outfitUrl = charData.outfitPreview;
    if (!outfitUrl) return;

    setState((p: any) => ({
      ...p,
      [char === 'A' ? 'charA' : 'charB']: { ...charData, isExtractingOutfit: true }
    }));

    try {
      const part = { mimeType: 'image/png', data: outfitUrl.split(',')[1] };
      const processedUrl = await service.extractOutfitImage(part);
      setState((p: any) => ({
        ...p,
        [char === 'A' ? 'charA' : 'charB']: { ...charData, processedOutfit: processedUrl, isExtractingOutfit: false }
      }));
    } catch (e) {
      setState((p: any) => ({
        ...p,
        [char === 'A' ? 'charA' : 'charB']: { ...charData, isExtractingOutfit: false }
      }));
      alert("Lỗi khi tách nền trang phục.");
    }
  };

  const processImportData = async (importedData: any) => {
    try {
      if (!Array.isArray(importedData) || importedData.length === 0) return;
      window.dispatchEvent(new CustomEvent('IMPORT_DATA_PROGRESS', { detail: { percent: 10, complete: false } }));

      const first = importedData[0];
      const inputs = first.inputs || {};
      const settings = inputs.settings || {};

      const newState = {
        ...state,
        productName: inputs.productName || state.productName,
        keyword: inputs.keyword || state.keyword,
        userContent: inputs.userContent || state.userContent,
        backgroundNote: inputs.backgroundNote || state.backgroundNote,
        scriptTone: settings.scriptTone || state.scriptTone,
        sceneCount: importedData.length, // Luôn lấy độ dài mảng làm số cảnh
        imageStyle: settings.imageStyle || state.imageStyle,
        charA: { ...state.charA, ...inputs.charA },
        charB: { ...state.charB, ...inputs.charB },
        productPreviews: inputs.productPreviews || [],
        script: {}, images: {}, videoPrompts: {}, sceneChars: {}, sceneSpeakers: {}
      };

      for (let i = 0; i < importedData.length; i++) {
        const item = importedData[i];
        const key = `v${i + 1}`;
        const itemInputs = item.inputs || {};
        const itemSettings = itemInputs.settings || {};

        newState.script[key] = item.script || '';
        newState.sceneChars[key] = itemInputs.sceneChar || (i % 2 === 0 ? 'A' : 'B');
        newState.sceneSpeakers[key] = itemInputs.sceneSpeaker || newState.sceneChars[key];
        newState.images[key] = {
          url: item.outputImage || '',
          loading: false,
          pose: itemSettings.pose || '',
          angle: itemSettings.angle || '',
          shot: itemSettings.shot || '',
          customPrompt: itemSettings.customPrompt || ''
        };
        newState.videoPrompts[key] = { 
          text: item.videoPrompt || '', 
          loading: false, 
          visible: !!item.videoPrompt 
        };

        const percent = Math.round(((i + 1) / importedData.length) * 100);
        window.dispatchEvent(new CustomEvent('IMPORT_DATA_PROGRESS', { detail: { percent, complete: i === importedData.length - 1 } }));
        await new Promise(r => setTimeout(r, 20));
      }
      setState(newState);
    } catch (e) { alert("Lỗi nạp dữ liệu!"); }
  };

  const constructExportData = () => {
    const keys = state.script ? Object.keys(state.script) : [];
    return keys.map((key, index) => ({
      stt: index + 1,
      inputs: {
        productName: state.productName,
        keyword: state.keyword,
        userContent: state.userContent,
        backgroundNote: state.backgroundNote,
        charA: { gender: state.charA.gender, voice: state.charA.voice, addressing: state.charA.addressing, description: state.charA.description, facePreview: state.charA.facePreview, processedOutfit: state.charA.processedOutfit, outfitPreview: state.charA.outfitPreview },
        charB: { gender: state.charB.gender, voice: state.charB.voice, addressing: state.charB.addressing, description: state.charB.description, facePreview: state.charB.facePreview, processedOutfit: state.charB.processedOutfit, outfitPreview: state.charB.outfitPreview },
        productPreviews: state.productPreviews,
        sceneChar: state.sceneChars[key],
        sceneSpeaker: state.sceneSpeakers[key],
        settings: {
          imageStyle: state.imageStyle,
          scriptTone: state.scriptTone,
          pose: state.images[key]?.pose || '',
          angle: state.images[key]?.angle || '',
          shot: state.images[key]?.shot || '',
          customPrompt: state.images[key]?.customPrompt || ''
        }
      },
      script: state.script[key],
      outputImage: state.images[key]?.url || '',
      videoPrompt: state.videoPrompts[key]?.text || ''
    }));
  };

  const handleLocalExportJson = () => {
    const exportData = constructExportData();
    const blob = new Blob([JSON.stringify(exportData, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `Review_DoiThoai_${Date.now()}.json`;
    link.click();
    URL.revokeObjectURL(url);
  };

  useEffect(() => {
    const handleGlobalExport = () => {
      const data = constructExportData();
      window.dispatchEvent(new CustomEvent('EXPORT_DATA_READY', { detail: { data, moduleName: 'Review_Doi_Thoai' } }));
    };
    const handleGlobalImport = (e: any) => processImportData(e.detail);
    window.addEventListener('REQUEST_EXPORT_DATA', handleGlobalExport);
    window.addEventListener('REQUEST_IMPORT_DATA', handleGlobalImport);
    return () => {
      window.removeEventListener('REQUEST_EXPORT_DATA', handleGlobalExport);
      window.removeEventListener('REQUEST_IMPORT_DATA', handleGlobalImport);
    };
  }, [state]);

  const handleGenerateScript = async () => {
    if (!state.productName) return alert("Thiếu tên sản phẩm");
    setState(p => ({ ...p, isGenerating: true }));
    try {
      const pParts = state.productFiles.length > 0 
        ? await Promise.all(state.productFiles.map(f => service.fileToGenerativePart(f)))
        : (state.productPreviews || []).map((url: string) => ({ mimeType: 'image/png', data: url.split(',')[1] }));
      const script = await service.generateDoiThoaiScript(pParts, state.productName, state.keyword, state.sceneCount, state.charA, state.charB, state.userContent, state.backgroundNote);
      const sceneChars: any = {};
      const sceneSpeakers: any = {};
      const initialImages: any = {};
      const initialPrompts: any = {};
      Object.keys(script).forEach((k, i) => {
          const defaultChar = (i % 2 === 0) ? 'A' : 'B';
          sceneChars[k] = defaultChar;
          sceneSpeakers[k] = defaultChar;
          initialImages[k] = { url: '', loading: false, pose: '', angle: '', shot: '', customPrompt: '' };
          initialPrompts[k] = { text: '', loading: false, visible: false };
      });
      setState(p => ({ ...p, script, sceneChars, sceneSpeakers, images: initialImages, videoPrompts: initialPrompts, isGenerating: false }));
    } catch (e) { setState(p => ({ ...p, isGenerating: false })); }
  };

  const handleGenImage = async (key: string) => {
    setState((p: any) => ({ ...p, images: { ...p.images, [key]: { ...p.images[key], loading: true } } }));
    try {
      const getB64Part = (url: string | null) => (url && url.startsWith('data:')) ? { mimeType: 'image/png', data: url.split(',')[1] } : null;

      const productParts = state.productFiles.length > 0 
        ? await Promise.all(state.productFiles.map((f: File) => service.fileToGenerativePart(f)))
        : (state.productPreviews || []).map((url: string) => getB64Part(url)).filter((p: any) => p !== null);

      const currentImg = state.images[key];
      const url = await service.generateDoiThoaiImage(
        productParts, 
        getB64Part(state.charA.facePreview), 
        getB64Part(state.charB.facePreview),
        getB64Part(state.charA.processedOutfit || state.charA.outfitPreview),
        getB64Part(state.charB.processedOutfit || state.charB.outfitPreview),
        state.productName, state.script[key], state.imageStyle, state.sceneChars[key],
        state.charA.gender, state.charB.gender, currentImg.pose || '', currentImg.angle || '',
        currentImg.shot || '', currentImg.customPrompt || '', null, state.backgroundNote
      );
      setState((p: any) => ({ ...p, images: { ...p.images, [key]: { ...currentImg, url, loading: false } } }));
    } catch (e) { 
      setState((p: any) => ({ ...p, images: { ...p.images, [key]: { ...p.images[key], loading: false, error: 'Lỗi' } } })); 
    }
  };

  const handleGenVideoPrompt = async (key: string) => {
    setState(p => ({ ...p, videoPrompts: { ...p.videoPrompts, [key]: { ...p.videoPrompts[key], loading: true, visible: true } } }));
    try {
      const speakerTag = state.sceneSpeakers[key];
      const speakerLabel = speakerTag === 'B' ? 'Nhân vật B' : (speakerTag === 'A' ? 'Nhân vật A' : 'Cả hai nhân vật');
      const speakerDescription = speakerTag === 'B' ? state.charB.description : state.charA.description;
      const gender = speakerTag === 'B' ? state.charB.gender : state.charA.gender;
      const voice = speakerTag === 'B' ? state.charB.voice : state.charA.voice;
      const currentImg = state.images[key];
      const prompt = await service.generateDoiThoaiVeoPrompt(
        state.productName, state.script[key], speakerLabel, speakerDescription,
        gender, voice, state.imageStyle, state.scriptTone, currentImg.shot || 'Medium Shot',
        state.backgroundNote, false, currentImg.url, state.productPreviews?.[0]?.split(',')[1]
      );
      setState(p => ({ ...p, videoPrompts: { ...p.videoPrompts, [key]: { text: prompt, loading: false, visible: true } } }));
    } catch (e) { setState(p => ({ ...p, videoPrompts: { ...p.videoPrompts, [key]: { ...p.videoPrompts[key], loading: false } } })); }
  };

  const handleBulkAction = async (type: 'image' | 'prompt') => {
    if (!state.script) return;
    for (const key of Object.keys(state.script)) {
      if (type === 'image') await handleGenImage(key); else await handleGenVideoPrompt(key);
    }
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      <div className="bg-white rounded-3xl p-8 border border-slate-200 shadow-sm mb-10">
        <div className="flex justify-between items-center mb-8 border-b pb-4">
           <h2 className="text-2xl font-black text-slate-800 uppercase tracking-tighter">Review Đối Thoại</h2>
           <span className="bg-orange-100 text-orange-600 text-[10px] font-black px-4 py-1.5 rounded-full uppercase tracking-widest">PRO 2.6 (Dialogue Lock)</span>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Nhân vật A */}
          <div className="space-y-4 bg-orange-50/30 p-6 rounded-2xl border border-orange-100">
            <h3 className="text-xs font-black text-orange-600 uppercase tracking-widest px-1">Nhân vật A</h3>
            <div className="grid grid-cols-2 gap-3">
              <div onClick={() => faceAInput.current?.click()} className="aspect-square border-2 border-dashed border-orange-200 rounded-xl flex items-center justify-center bg-white cursor-pointer overflow-hidden relative group">
                {state.charA.facePreview ? (
                  <>
                    <img src={state.charA.facePreview} className="h-full object-cover w-full" />
                    <button 
                      type="button"
                      onClick={(e) => { e.stopPropagation(); setState(p => ({ ...p, charA: { ...p.charA, facePreview: null } })); }} 
                      className="absolute top-1 right-1 bg-red-600 text-white p-1 rounded-full shadow-lg opacity-0 group-hover:opacity-100 transition-opacity z-10"
                    >
                      <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12"/></svg>
                    </button>
                  </>
                ) : <span className="text-[9px] font-bold text-slate-400 uppercase">Mặt A</span>}
                <input type="file" ref={faceAInput} className="hidden" onChange={e => { const f = e.target.files?.[0]; if (f) { const r = new FileReader(); r.onload = (ev) => setState(p => ({ ...p, charA: { ...p.charA, facePreview: ev.target?.result as string } })); r.readAsDataURL(f); } }} />
              </div>
              <div onClick={() => outfitAInput.current?.click()} className="aspect-square border-2 border-dashed border-orange-200 rounded-xl flex items-center justify-center bg-white cursor-pointer overflow-hidden relative group">
                {state.charA.outfitPreview ? (
                  <>
                    <img src={state.charA.processedOutfit || state.charA.outfitPreview} className="h-full object-cover w-full" />
                    <button 
                      type="button"
                      onClick={(e) => { e.stopPropagation(); setState(p => ({ ...p, charA: { ...p.charA, outfitPreview: null, processedOutfit: null } })); }} 
                      className="absolute top-1 right-1 bg-red-600 text-white p-1 rounded-full shadow-lg opacity-0 group-hover:opacity-100 transition-opacity z-10"
                    >
                      <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12"/></svg>
                    </button>
                  </>
                ) : <span className="text-[9px] font-bold text-slate-400 uppercase">Đồ A</span>}
                <input type="file" ref={outfitAInput} className="hidden" onChange={e => { const f = e.target.files?.[0]; if (f) { const r = new FileReader(); r.onload = (ev) => setState(p => ({ ...p, charA: { ...p.charA, outfitPreview: ev.target?.result as string, processedOutfit: null } })); r.readAsDataURL(f); } }} />
              </div>
            </div>
            {state.charA.outfitPreview && (
                <button 
                  onClick={() => handleExtractOutfit('A')} 
                  disabled={state.charA.isExtractingOutfit}
                  className={`w-full py-1.5 rounded-lg text-[9px] font-black uppercase transition-all ${state.charA.processedOutfit ? 'bg-green-100 text-green-700' : 'bg-orange-600 text-white hover:bg-orange-700'}`}
                >
                  {state.charA.isExtractingOutfit ? "Đang xử lý..." : state.charA.processedOutfit ? "Đã tách nền ✓" : "Tách nền Đồ A"}
                </button>
            )}
            <div className="grid grid-cols-2 gap-2">
              <select value={state.charA.gender} onChange={e => setState(p => ({ ...p, charA: { ...p.charA, gender: e.target.value } }))} className="w-full p-3 bg-white border border-orange-100 rounded-xl font-bold text-xs"><option value="Nữ">Nữ</option><option value="Nam">Nam</option></select>
              <select value={state.charA.voice} onChange={e => setState(p => ({ ...p, charA: { ...p.charA, voice: e.target.value } }))} className="w-full p-3 bg-white border border-orange-100 rounded-xl font-bold text-[10px]">{VOICE_OPTIONS.map(v => <option key={v} value={v}>{v}</option>)}</select>
            </div>
            <input list="doi-thoai-addr-a" value={state.charA.addressing} onChange={e => setState(p => ({ ...p, charA: { ...p.charA, addressing: e.target.value } }))} className="w-full p-3 bg-white border border-orange-100 rounded-xl font-bold text-xs" placeholder="Xưng hô A" />
            <datalist id="doi-thoai-addr-a">{ADDRESSING_OPTIONS.map(o => <option key={o} value={o} />)}</datalist>
            <textarea value={state.charA.description} onChange={e => setState(p => ({ ...p, charA: { ...p.charA, description: e.target.value } }))} placeholder="Mô tả ngoại hình A" className="w-full p-3 bg-white border border-orange-100 rounded-xl font-bold text-xs resize-none h-16" />
          </div>

          {/* Nhân vật B */}
          <div className="space-y-4 bg-blue-50/30 p-6 rounded-2xl border border-blue-100">
            <h3 className="text-xs font-black text-blue-600 uppercase tracking-widest px-1">Nhân vật B</h3>
            <div className="grid grid-cols-2 gap-3">
              <div onClick={() => faceBInput.current?.click()} className="aspect-square border-2 border-dashed border-blue-200 rounded-xl flex items-center justify-center bg-white cursor-pointer overflow-hidden relative group">
                {state.charB.facePreview ? (
                  <>
                    <img src={state.charB.facePreview} className="h-full object-cover w-full" />
                    <button 
                      type="button"
                      onClick={(e) => { e.stopPropagation(); setState(p => ({ ...p, charB: { ...p.charB, facePreview: null } })); }} 
                      className="absolute top-1 right-1 bg-red-600 text-white p-1 rounded-full shadow-lg opacity-0 group-hover:opacity-100 transition-opacity z-10"
                    >
                      <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12"/></svg>
                    </button>
                  </>
                ) : <span className="text-[9px] font-bold text-slate-400 text-center uppercase">Mặt B</span>}
                <input type="file" ref={faceBInput} className="hidden" onChange={e => { const f = e.target.files?.[0]; if (f) { const r = new FileReader(); r.onload = (ev) => setState(p => ({ ...p, charB: { ...p.charB, facePreview: ev.target?.result as string } })); r.readAsDataURL(f); } }} />
              </div>
              <div onClick={() => outfitBInput.current?.click()} className="aspect-square border-2 border-dashed border-blue-200 rounded-xl flex items-center justify-center bg-white cursor-pointer overflow-hidden relative group">
                {state.charB.outfitPreview ? (
                  <>
                    <img src={state.charB.processedOutfit || state.charB.outfitPreview} className="h-full object-cover w-full" />
                    <button 
                      type="button"
                      onClick={(e) => { e.stopPropagation(); setState(p => ({ ...p, charB: { ...p.charB, outfitPreview: null, processedOutfit: null } })); }} 
                      className="absolute top-1 right-1 bg-red-600 text-white p-1 rounded-full shadow-lg opacity-0 group-hover:opacity-100 transition-opacity z-10"
                    >
                      <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12"/></svg>
                    </button>
                  </>
                ) : <span className="text-[9px] font-bold text-slate-400 text-center uppercase">Đồ B</span>}
                <input type="file" ref={outfitBInput} className="hidden" onChange={e => { const f = e.target.files?.[0]; if (f) { const r = new FileReader(); r.onload = (ev) => setState(p => ({ ...p, charB: { ...p.charB, outfitPreview: ev.target?.result as string, processedOutfit: null } })); r.readAsDataURL(f); } }} />
              </div>
            </div>
            {state.charB.outfitPreview && (
                <button 
                  onClick={() => handleExtractOutfit('B')} 
                  disabled={state.charB.isExtractingOutfit}
                  className={`w-full py-1.5 rounded-lg text-[9px] font-black uppercase transition-all ${state.charB.processedOutfit ? 'bg-green-100 text-green-700' : 'bg-blue-600 text-white hover:bg-blue-700'}`}
                >
                  {state.charB.isExtractingOutfit ? "Đang xử lý..." : state.charB.processedOutfit ? "Đã tách nền ✓" : "Tách nền Đồ B"}
                </button>
            )}
            <div className="grid grid-cols-2 gap-2">
              <select value={state.charB.gender} onChange={e => setState(p => ({ ...p, charB: { ...p.charB, gender: e.target.value } }))} className="w-full p-3 bg-white border border-blue-100 rounded-xl font-bold text-xs"><option value="Nữ">Nữ</option><option value="Nam">Nam</option></select>
              <select value={state.charB.voice} onChange={e => setState(p => ({ ...p, charB: { ...p.charB, voice: e.target.value } }))} className="w-full p-3 bg-white border border-blue-100 rounded-xl font-bold text-[10px]">{VOICE_OPTIONS.map(v => <option key={v} value={v}>{v}</option>)}</select>
            </div>
            <input list="doi-thoai-addr-b" value={state.charB.addressing} onChange={e => setState(p => ({ ...p, charB: { ...p.charB, addressing: e.target.value } }))} className="w-full p-3 bg-white border border-blue-100 rounded-xl font-bold text-xs" placeholder="Xưng hô B" />
            <datalist id="doi-thoai-addr-b">{ADDRESSING_OPTIONS.map(o => <option key={o} value={o} />)}</datalist>
            <textarea value={state.charB.description} onChange={e => setState(p => ({ ...p, charB: { ...p.charB, description: e.target.value } }))} placeholder="Mô tả ngoại hình B" className="w-full p-3 bg-white border border-blue-100 rounded-xl font-bold text-xs resize-none h-16" />
          </div>

          {/* Cài đặt chung */}
          <div className="space-y-4">
            <h3 className="text-xs font-black text-slate-500 uppercase tracking-widest px-1">Nội dung & Sản phẩm</h3>
            <div className="grid grid-cols-2 gap-3">
              <div onClick={() => productInput.current?.click()} className="aspect-square border-2 border-dashed border-slate-200 rounded-xl flex items-center justify-center bg-slate-50 cursor-pointer overflow-hidden relative group">
                {state.productPreviews?.[0] ? (
                  <>
                    <img src={state.productPreviews[0]} className="h-full object-contain" />
                    <button 
                      type="button"
                      onClick={(e) => { e.stopPropagation(); setState(p => ({ ...p, productFiles: [], productPreviews: [] })); }} 
                      className="absolute top-1 right-1 bg-red-600 text-white p-1 rounded-full shadow-lg opacity-0 group-hover:opacity-100 transition-opacity z-10"
                    >
                      <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12"/></svg>
                    </button>
                  </>
                ) : <span className="text-[9px] font-bold text-slate-400 uppercase">Ảnh SP</span>}
                <input type="file" multiple ref={productInput} className="hidden" onChange={e => { if (!e.target.files) return; const files = Array.from(e.target.files); Promise.all(files.map(f => new Promise((resolve) => { const r = new FileReader(); r.onload = (ev) => resolve(ev.target?.result); r.readAsDataURL(f); }))).then(results => setState(p => ({ ...p, productFiles: files, productPreviews: results }))); }} />
              </div>
              <textarea 
                value={state.backgroundNote} 
                onChange={e => setState(p => ({ ...p, backgroundNote: e.target.value }))}
                placeholder="Ghi chú bối cảnh (Ví dụ: Phòng khách sang trọng, ánh sáng ấm, phong cách vintage...)"
                className="aspect-square border-2 border-slate-200 rounded-xl p-4 bg-slate-50 text-xs font-bold focus:ring-2 focus:ring-indigo-100 outline-none resize-none leading-relaxed placeholder:text-slate-300 shadow-inner"
              />
            </div>
            <input type="text" value={state.productName} onChange={e => setState(p => ({ ...p, productName: e.target.value }))} placeholder="Tên sản phẩm..." className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl font-bold text-xs outline-none" />
            <textarea value={state.userContent} onChange={e => setState(p => ({ ...p, userContent: e.target.value }))} placeholder="Ý tưởng kịch bản..." className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl h-24 text-xs font-bold focus:ring-2 focus:ring-orange-100 outline-none resize-none leading-relaxed" />
            <div className="grid grid-cols-2 gap-3">
              <select value={state.scriptTone} onChange={e => setState(p => ({ ...p, scriptTone: e.target.value }))} className="w-full p-3 bg-white border border-slate-200 rounded-xl font-bold text-xs">{TONE_OPTIONS.map(o => <option key={o} value={o}>{o}</option>)}</select>
              <select value={state.sceneCount} onChange={e => setState(p => ({ ...p, sceneCount: parseInt(e.target.value) }))} className="w-full p-3 bg-white border border-slate-200 rounded-xl font-bold text-orange-600 text-xs">
                {SCENE_COUNT_OPTIONS.map(o => <option key={o.count} value={o.count}>{o.label}</option>)}
              </select>
            </div>
            <button onClick={handleGenerateScript} disabled={state.isGenerating} className="w-full py-4 bg-orange-600 text-white font-black rounded-xl shadow-lg uppercase text-xs hover:bg-orange-700 active:scale-95 disabled:opacity-50">{state.isGenerating ? "Đang tạo..." : "TẠO KỊCH BẢN PV"}</button>
          </div>
        </div>
      </div>

      {state.script && (
        <div className="space-y-12 pb-32">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-6">
            {Object.keys(state.script).map((key, idx) => {
              const char = state.sceneChars[key];
              return (
                <div key={key} className="space-y-4 animate-fadeIn">
                  <div className={`p-2 rounded-xl text-[9px] font-black uppercase text-center border-b-2 ${char === 'A' ? 'bg-orange-50 text-orange-600' : 'bg-blue-50 text-blue-600'}`}>Mẫu {char} nói</div>
                  <ScriptSection title={`Cảnh ${idx + 1}`} content={state.script[key]} color={char === 'A' ? 'border-orange-500' : 'border-blue-500'} onChange={v => setState(p => ({ ...p, script: { ...p.script, [key]: v } }))} />
                  <div className="flex bg-slate-100 p-1 rounded-xl"><button onClick={() => setState(p => ({ ...p, sceneChars: { ...p.sceneChars, [key]: 'A' } }))} className={`flex-1 py-1.5 text-[9px] font-black rounded-lg ${char === 'A' ? 'bg-white shadow text-slate-800' : 'text-slate-400'}`}>Mẫu A</button><button onClick={() => setState(p => ({ ...p, sceneChars: { ...p.sceneChars, [key]: 'B' } }))} className={`flex-1 py-1.5 text-[9px] font-black rounded-lg ${char === 'B' ? 'bg-white shadow text-slate-800' : 'text-slate-400'}`}>Mẫu B</button></div>
                  <ImageCard label={`Cảnh ${idx+1}`} imageData={state.images[key]} videoPrompt={state.videoPrompts[key]} onRegenerate={() => handleGenImage(key)} onGeneratePrompt={() => handleGenVideoPrompt(key)} onTranslate={() => {}} pose={state.images[key].pose} onPoseChange={v => setState(p => ({ ...p, images: { ...p.images, [key]: { ...p.images[key], pose: v } } }))} angle={state.images[key].angle} onAngleChange={v => setState(p => ({ ...p, images: { ...p.images, [key]: { ...p.images[key], angle: v } } }))} customPrompt={state.images[key].customPrompt} onCustomPromptChange={v => setState(p => ({ ...p, images: { ...p.images, [key]: { ...p.images[key], customPrompt: v } } }))} />
                </div>
              );
            })}
          </div>

          <div className="flex flex-col gap-10 py-12 border-t border-slate-200">
            <div className="flex flex-col md:flex-row items-center justify-center gap-4">
              <button onClick={() => handleBulkAction('image')} className="w-full md:w-auto px-10 py-4 bg-orange-600 text-white font-black rounded-2xl shadow-xl hover:scale-105 active:scale-95 transition-all text-xs uppercase">Vẽ tất cả ảnh</button>
              <button onClick={() => handleBulkAction('prompt')} className="w-full md:w-auto px-10 py-4 bg-slate-900 text-white font-black rounded-2xl shadow-xl hover:scale-105 active:scale-95 transition-all text-xs uppercase">Tạo tất cả prompt</button>
            </div>

            <div className="flex flex-col md:flex-row items-center justify-center gap-4 pt-4">
               <button onClick={() => localJsonRef.current?.click()} className="w-full md:w-auto px-10 py-4 bg-slate-100 text-slate-600 font-black rounded-2xl border border-slate-200 hover:bg-slate-200 transition-all flex items-center justify-center gap-3 uppercase text-[11px] tracking-widest shadow-sm">Tải Dự Án (JSON)</button>
               <input type="file" ref={localJsonRef} onChange={e => { const file = e.target.files?.[0]; if (file) { const reader = new FileReader(); reader.onload = (event) => { try { processImportData(JSON.parse(event.target?.result as string)); } catch (err) { alert("File JSON không hợp lệ!"); } }; r.readAsDataURL(f); } e.target.value = ""; }} className="hidden" accept="application/json" />
               <button onClick={handleLocalExportJson} className="w-full md:w-auto px-10 py-4 bg-indigo-600 text-white font-black rounded-2xl hover:bg-indigo-700 transition-all flex items-center justify-center gap-3 uppercase text-[11px] tracking-widest shadow-lg">Lưu Dự Án (JSON)</button>
            </div>

            <div className="flex flex-col md:flex-row items-center justify-center gap-6">
                <button onClick={async () => { 
                    if (typeof JSZip === 'undefined') return alert("ZIP error"); 
                    const zip = new JSZip(); 
                    let count = 0; 
                    if (state.images) {
                      Object.keys(state.images).forEach((k, i) => { if (state.images[k].url) { zip.file(`${String(i + 1).padStart(2, '0')}.png`, state.images[k].url.split(',')[1], { base64: true }); count++; } }); 
                    }
                    if (count === 0) return alert("Không có ảnh"); 
                    const content = await (zip as any).generateAsync({ type: "blob" }); 
                    const link = document.createElement('a'); 
                    link.href = URL.createObjectURL(content as any); 
                    link.download = `review_doithoai_images.zip`; 
                    link.click(); 
                }} className="w-full md:w-auto px-12 py-5 bg-slate-900 text-white font-black rounded-3xl shadow-xl hover:bg-black transition-all flex items-center justify-center gap-3 uppercase tracking-widest text-base">Tải bộ ảnh (ZIP)</button>
                <button onClick={() => { if (state.videoPrompts) { const text = Object.keys(state.videoPrompts).map(k => state.videoPrompts[k].text).filter(t => t).join('\n'); if (!text) return alert("Chưa có prompt"); const blob = new Blob([text], { type: 'text/plain' }); const link = document.createElement('a'); link.href = URL.createObjectURL(blob); link.download = 'prompts_doithoai.txt'; link.click(); } }} className="w-full md:w-auto px-12 py-5 bg-orange-600 text-white font-black rounded-3xl shadow-xl hover:bg-orange-700 transition-all flex items-center justify-center gap-3 uppercase tracking-widest text-base">Tải Prompt (TXT)</button>
            </div>
          </div>
        </div>
      )}
    </div>
  ); 
};

export default ReviewDoiThoaiModule;
